// ─── REVEAL ANIMATION (IntersectionObserver) ───────────────

dom.ready(() => {
  let observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.classList.add('visible')
      }
    })
  }, { threshold: 0.1 })

  document.querySelectorAll('.reveal').forEach(el => observer.observe(el))
})

// ─── CAROUSEL LOGIC ────────────────────────────────────────

dom.ready(() => {
  let carousels = [
    { trackId: 'layerTrack', dotsId: 'layerDots' },
    { trackId: 'constructTrack', dotsId: 'constructDots' }
  ]

  carousels.forEach(cfg => {
    let track = document.getElementById(cfg.trackId)
    let dotsContainer = document.getElementById(cfg.dotsId)
    if (!track || !dotsContainer) return

    let slides = track.children
    let count = slides.length
    let current = 0

    // Build dots
    for (let i = 0; i < count; i++) {
      let dot = document.createElement('button')
      dot.className = 'carousel-dot' + (i === 0 ? ' active' : '')
      dot.setAttribute('aria-label', 'Slide ' + (i + 1))
      dot.addEventListener('click', () => goTo(i))
      dotsContainer.appendChild(dot)
    }

    let goTo = (index) => {
      current = index
      track.style.transform = 'translateX(-' + (current * 100) + '%)'
      let dots = dotsContainer.querySelectorAll('.carousel-dot')
      dots.forEach((d, i) => {
        if (i === current) {
          d.classList.add('active')
        } else {
          d.classList.remove('active')
        }
      })
    }

    // Auto-rotate every 6 seconds
    setInterval(() => {
      goTo((current + 1) % count)
    }, 6000)
  })
})


